":"裸妝唇","zh_tw":"裸妝唇","en":"裸妝唇"},{"zh_hk":"薰腳","zh_mo":"薰腳","zh_tw":"薰腳","en":"薰腳"},{"zh_hk":"脫斑/疣/癦/肉粒","zh_mo":"脫斑/疣/癦/肉粒","zh_tw":"脫斑/疣/癦/肉粒","en":"脫斑/疣/癦/肉粒"},{"zh_hk":"脫疣/斑","zh_mo":"脫疣/斑","zh_tw":"脫疣/斑","en":"脫疣/斑"},{"zh_hk":"柔紡繡眼線","zh_mo":"柔紡繡眼線","zh_tw":"柔紡繡眼線","en":"柔紡繡眼線"},{"zh_hk":"日本3D眼睫毛","zh_mo":"日本3D眼睫毛","zh_tw":"日本3D眼睫毛","en":"日本3D眼睫毛"},{"zh_hk":"卵巢養護","zh_mo":"卵巢養護","zh_tw":"卵巢養護","en":"卵巢養護"}]';

        $id = 1;
        $translation = [];
        $tags = json_decode($tags);

        for ($i = 0; $i < 3; $i++) {
            foreach ($tags as $tag) {
                $translation[$id++] = $tag;
            }
        }

        $translations = [
            [
                'table' => 'tags',
                'column' => 'name',
                'translation' => $translation
            ]
        ];

        $values = array_map(function ($translation) {
            $json = json_encode($translation['translation'], JSON_UNESCAPED_UNICODE);
            $json = addslashes($json);
            return "('{$translation['table']}', '{$translation['column']}', '{$json}')";
        }, $translations);

        $sql = "INSERT INTO translations (`table`, `column`, `translation`) VALUES " . implode(', ', $values);

        DB::insert($sql);

        $regions = ['hk', 'mo', 'tw'];
        $id = 1;
        $now = now();
        $values = [];

        foreach ($regions as $region) {
            for ($i = 1; $i <= count($tags); $i++) {
                $values[] = [
                    'id' => $id,
                    'region' => $region,
                    'created_at' => $now,
                    'updated_at' => $now,
                ];
                $id += 1;
            }
        }

        DB::table('tags')->insert($values);
    }
